// src/components/panels/AIChatPanel.jsx - VERSI FINAL YANG BEKERJA
import React, { useState, useRef, useEffect } from 'react';
import { aiAPI } from '../../services/api';
import useStore from '../../store/useStore';

const QUICK = [
  'Ada kemacetan di Palembang sekarang?',
  'SPBU terdekat dari lokasi saya',
  'Kondisi cuaca Palembang hari ini',
  'Rute tercepat ke Jembatan Ampera',
  'Tips berkendara saat hujan',
  'Area mana yang paling ramai permintaan driver?',
];

export default function AIChatPanel({ isOpen, onClose, userLocation, weather, route, destination }) {
  const { aiMessages, addAIMessage, user } = useStore();
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef(null);

  // Greeting
  useEffect(() => {
    if (aiMessages.length === 0) {
      const h = new Date().getHours();
      const gr = h < 12 ? 'Selamat pagi' : h < 17 ? 'Selamat siang' : 'Selamat sore';
      addAIMessage({
        role: 'assistant',
        content: `${gr}! Saya RouteAI, asisten navigasi cerdas Anda.\n\nKetik pertanyaan Anda!`,
        ts: new Date()
      });
    }
  }, []);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [aiMessages, loading]);

  const send = async (text) => {
    const msg = (text || input).trim();
    if (!msg || loading) return;
    setInput('');
    addAIMessage({ role: 'user', content: msg, ts: new Date() });
    setLoading(true);
    try {
      const history = aiMessages.slice(-8).map(m => ({ role: m.role, content: m.content }));
      const context = {
        city: 'Palembang',
        weather: weather?.temperature ? `${weather.temperature}°C, ${weather.description}` : 'Berawan',
        userLocation: userLocation ? `${userLocation.lat},${userLocation.lng}` : 'Palembang',
        activeRoute: destination ? { to: destination.name } : null,
        vehicle: user?.preferences?.vehicle || 'Mobil'
      };
      const res = await aiAPI.chat(msg, history, context);
      addAIMessage({ role: 'assistant', content: res.data.data.reply, ts: new Date() });
    } catch (err) {
      addAIMessage({ role: 'assistant', content: 'Maaf, AI sedang sibuk. Coba lagi nanti.', ts: new Date() });
    }
    setLoading(false);
  };

  if (!isOpen) return null;

  return (
    <div style={{
      position: 'fixed',
      bottom: 0,
      left: 0,
      right: 0,
      background: '#161B22',
      borderTop: '0.5px solid rgba(255,255,255,0.1)',
      borderTopLeftRadius: 20,
      borderTopRightRadius: 20,
      zIndex: 200,
      maxHeight: '80vh',
      display: 'flex',
      flexDirection: 'column',
      boxShadow: '0 -4px 20px rgba(0,0,0,0.3)'
    }}>
      {/* Header */}
      <div style={{
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        padding: '12px 16px',
        borderBottom: '0.5px solid rgba(255,255,255,0.07)'
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          <div style={{ width: 32, height: 32, borderRadius: 8, background: '#6B5CE7', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2"><path d="M12 2a2 2 0 012 2c0 .74-.4 1.39-1 1.73V7h1a7 7 0 017 7h1a1 1 0 011 1v3a1 1 0 01-1 1h-1v1a2 2 0 01-2 2H5a2 2 0 01-2-2v-1H2a1 1 0 01-1-1v-3a1 1 0 011-1h1a7 7 0 017-7h1V5.73A2 2 0 0110 4a2 2 0 012-2z"/></svg>
          </div>
          <div>
            <div style={{ fontSize: 15, fontWeight: 600 }}>RouteAI Assistant</div>
            <div style={{ fontSize: 10, color: '#1FAD8E' }}>Online — Claude AI</div>
          </div>
        </div>
        <button onClick={onClose} style={{ background: 'none', border: 'none', color: '#8B949E', fontSize: 20, cursor: 'pointer' }}>✕</button>
      </div>

      {/* Quick prompts - scroll horizontal */}
      <div style={{ padding: '12px 16px 0', flexShrink: 0 }}>
        <div style={{ display: 'flex', gap: 8, overflowX: 'auto', paddingBottom: 8 }}>
          {QUICK.map((q, i) => (
            <button key={i} onClick={() => send(q)} style={{ whiteSpace: 'nowrap', padding: '6px 14px', background: '#21262D', borderRadius: 20, fontSize: 12, border: 'none', color: '#F0F6FC' }}>
              {q}
            </button>
          ))}
        </div>
      </div>

      {/* Messages - scrollable */}
      <div ref={scrollRef} style={{ flex: 1, overflowY: 'auto', padding: '12px 16px', maxHeight: '50vh' }}>
        {aiMessages.map((m, i) => (
          <div key={i} style={{ marginBottom: 12, textAlign: m.role === 'user' ? 'right' : 'left' }}>
            <div style={{ display: 'inline-block', maxWidth: '80%', padding: '8px 12px', borderRadius: 16, background: m.role === 'user' ? '#6B5CE7' : '#21262D', color: '#F0F6FC' }}>
              {m.role === 'assistant' && <strong style={{ color: '#7B6FFF' }}>RouteAI</strong>}
              <div style={{ whiteSpace: 'pre-line', marginTop: 4 }}>{m.content}</div>
            </div>
          </div>
        ))}
        {loading && (
          <div style={{ textAlign: 'left' }}>
            <div className="loading-dots" style={{ padding: 8, background: '#21262D', borderRadius: 16, display: 'inline-block' }}>
              <div className="loading-dot"/><div className="loading-dot"/><div className="loading-dot"/>
            </div>
          </div>
        )}
      </div>

      {/* Input - fixed di bawah */}
      <div style={{ padding: '12px 16px', borderTop: '0.5px solid rgba(255,255,255,0.07)', display: 'flex', gap: 8, background: '#161B22', borderBottomLeftRadius: 20, borderBottomRightRadius: 20 }}>
        <input
          style={{ flex: 1, padding: '10px 12px', background: '#0D1117', border: '0.5px solid rgba(255,255,255,0.1)', borderRadius: 24, color: '#F0F6FC', outline: 'none' }}
          placeholder="Tanya RouteAI..."
          value={input}
          onChange={e => setInput(e.target.value)}
          onKeyPress={e => e.key === 'Enter' && send()}
          autoFocus
        />
        <button onClick={() => send()} style={{ padding: '8px 20px', background: '#6B5CE7', border: 'none', borderRadius: 24, color: '#fff', fontWeight: 600 }}>Kirim</button>
      </div>
    </div>
  );
}
